import { Request, Response } from 'express';
import Listing from '../models/Listing.js';
import Room from '../models/Room.js';
import Review from '../models/Review.js';

export const getListings = async (req: Request, res: Response) => {
    try {
        const { priceMin, priceMax, amenities, limit, sort, has3DView } = req.query;
        let query: any = {};

        if (priceMin) {
            query.priceMin = { ...query.priceMin, $gte: Number(priceMin) };
        }
        if (priceMax) {
            query.priceMax = { ...query.priceMax, $lte: Number(priceMax) };
        }

        if (amenities) {
            const amenitiesArray = Array.isArray(amenities) ? amenities : [amenities];
            query.amenities = { $all: amenitiesArray };
        }

        if (has3DView === 'true') {
            // This is a bit tricky as rooms are separate. We might need to find listingIds that have rooms with model3dUrl.
            const roomsWith3D = await Room.find({ model3dUrl: { $exists: true, $ne: '' } }).select('listingId');
            const listingIds = roomsWith3D.map(r => r.listingId);
            query._id = { $in: listingIds };
        }

        const maxResults = limit ? Math.min(Number(limit), 100) : 50;

        let sortOption: any = { createdAt: -1 };
        if (sort === 'price_asc') sortOption = { priceMin: 1 };
        if (sort === 'price_desc') sortOption = { priceMin: -1 };

        const listings = await Listing.find(query)
            .populate('ownerId', 'name avatar')
            .limit(maxResults)
            .sort(sortOption);
        res.json(listings);
    } catch (error) {
        console.error('Error fetching listings:', error);
        res.status(500).json({ message: 'Server error' });
    }
};

