export const createListing = async (req: Request, res: Response) => {
    try {
        const { name, address, priceMin, priceMax, totalRooms, availableRooms, amenities, rules, location, photos, rooms, type, propertyDetails } = req.body;

        // Extract ownerId from request (assuming auth middleware attaches user)
        const ownerId = (req as any).user?._id || req.body.ownerId;

        if (!ownerId) {
            res.status(400).json({ message: 'Owner ID required' });
            return;
        }

        const listing = new Listing({
            ownerId,
            name,
            address,
            priceMin,
            priceMax,
            totalRooms,
            availableRooms,
            amenities,
            rules,
            location,
            photos,
            type,
            propertyDetails
        });

        const createdListing = await listing.save();

        if (rooms && Array.isArray(rooms) && rooms.length > 0) {
            const roomDocs = rooms.map(room => ({
                listingId: createdListing._id,
                type: room.type || 'Standard',
